// src/rules/yoPairs.ts
var YO_MAP = (() => {
  const map = /* @__PURE__ */ new Map();
  for (let line of eyo_safe_default.split("\n")) {
    line = line.split("#")[0].trim();
    if (!line || line.startsWith("_")) continue;
    const m = line.match(/^([^(]+)\(([^)]*)\)\s*$/);
    const forms = m ? m[2].split("|").map((suf) => m[1] + suf) : [line];
    for (const form of forms) {
      if (!/[ёЁ]/.test(form)) continue;
      const key = form.toLowerCase().replace(/ё/g, "\u0435");
      map.set(key, form.toLowerCase());
    }
  }
  return map;
})();
var WORD_RE = /[А-Яа-яЁё]+/g;
function applyYoFix(text) {
  return text.replace(WORD_RE, (word) => {
    const key = word.toLowerCase().replace(/ё/g, "\u0435");
    const canon = YO_MAP.get(key);
    if (!canon) return word;
    return preserveCase(canon, word, "first", "ru");
  });
}

